import React, { useContext } from 'react';
import { Link } from 'react-router-dom';
import Layout from '../components/PageLayout';
import products from '../data/products';
import { CartContext } from '../context/CartContext';

const ProductCatalog = () => {
  const { addToCart } = useContext(CartContext);

  const handleBuyNow = (product) => {
    if (product.url) {
      window.open(product.url, '_blank');
      setTimeout(() => {
        window.focus();
      }, 100);
    } else {
      alert('Stripe link coming soon for this product!');
    }
  };

  const handleAddToCart = (product) => {
    const productWithId = { ...product, id: product.name };
    addToCart(productWithId);
    alert(`✅ ${product.name} added to cart!`);
  };

  const seaMossProducts = products.filter(p => p.category === 'Sea Moss');
  const herbProducts = products.filter(p => p.category === 'Herbs');
  const seedProducts = products.filter(p => p.category === 'Seeds');
  const oilProducts = products.filter(p => p.category === 'Oils');
  const kitProducts = products.filter(p => p.category === 'Kits' || p.name.includes('Kit') || p.name.includes('777') || p.name.includes('Chelation') || p.name.includes('Diabetes') || p.name.includes('Blood Pressure') || p.name.includes('Autoimmune'));
  const snackProducts = products.filter(p => p.category === 'Snacks' || p.category === 'AV Snacks');
  const beverageProducts = products.filter(p => p.category === 'Beverages' || p.category === 'AV Drinks');
  const j2eProducts = products.filter(p => p.category === 'J2E' || p.name.includes('J2E') || p.name.includes('Journey') || p.name.includes('Accommodation'));
  const merchandiseProducts = products.filter(p => p.category === 'Merchandise');

  const CategorySection = ({ title, products, color, icon, id }) => (
    <div id={id} style={{ marginBottom: '80px' }}>
      <h2 style={{
        fontSize: 'clamp(2rem, 4vw, 3rem)',
        color: color,
        marginBottom: '15px',
        display: 'flex',
        alignItems: 'center',
        gap: '15px'
      }}>
        <span style={{ fontSize: '2.5rem' }}>{icon}</span>
        {title}
      </h2>
      <div style={{
        height: '4px',
        background: `linear-gradient(90deg, ${color}, transparent)`,
        marginBottom: '40px',
        borderRadius: '2px'
      }} />
      
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
        gap: '30px'
      }}>
        {products.map((product, i) => (
          <div
            key={i}
            style={{
              background: 'rgba(0,0,0,0.7)',
              borderRadius: '15px',
              border: `3px solid ${color}`,
              overflow: 'hidden',
              boxShadow: `0 5px 20px ${color}40`,
              transition: 'all 0.3s'
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = 'translateY(-10px)';
              e.currentTarget.style.boxShadow = `0 15px 40px ${color}80`;
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.boxShadow = `0 5px 20px ${color}40`;
            }}
          >
            <div style={{
              height: '220px',
              backgroundImage: `url(${product.image})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center'
            }} />
            
            <div style={{ padding: '25px' }}>
              <div style={{
                background: color,
                color: '#000',
                padding: '5px 12px',
                borderRadius: '10px',
                fontSize: '0.8rem',
                fontWeight: 'bold',
                display: 'inline-block',
                marginBottom: '12px'
              }}>
                {product.category}
              </div>

              <h3 style={{
                color: '#FFD700',
                fontSize: '1.15rem',
                marginBottom: '12px',
                minHeight: '55px',
                lineHeight: '1.3'
              }}>
                {product.name}
              </h3>
              
              <p style={{
                color: '#DDD6B8',
                fontSize: '0.95rem',
                marginBottom: '18px',
                minHeight: '60px',
                lineHeight: '1.5'
              }}>
                {product.description}
              </p>

              <div style={{
                fontSize: '2rem',
                fontWeight: 'bold',
                color: color,
                marginBottom: '18px'
              }}>
                ${product.price.toFixed(2)}
              </div>

              <div style={{ display: 'flex', gap: '12px', marginBottom: '15px' }}>
                <button
                  onClick={() => handleBuyNow(product)}
                  style={{
                    flex: 1,
                    padding: '15px',
                    background: 'linear-gradient(135deg, #FFD700, #FFA500)',
                    border: 'none',
                    borderRadius: '10px',
                    color: '#000',
                    fontSize: '1.05rem',
                    fontWeight: 'bold',
                    cursor: 'pointer',
                    transition: 'all 0.3s'
                  }}
                  onMouseEnter={(e) => e.target.style.transform = 'scale(1.05)'}
                  onMouseLeave={(e) => e.target.style.transform = 'scale(1)'}
                >
                  BUY NOW
                </button>
                
                <button
                  onClick={() => handleAddToCart(product)}
                  style={{
                    padding: '15px 18px',
                    background: `${color}33`,
                    border: `2px solid ${color}`,
                    borderRadius: '10px',
                    color: color,
                    fontSize: '1.4rem',
                    cursor: 'pointer',
                    transition: 'all 0.3s'
                  }}
                  onMouseEnter={(e) => {
                    e.target.style.background = `${color}66`;
                    e.target.style.transform = 'scale(1.15)';
                  }}
                  onMouseLeave={(e) => {
                    e.target.style.background = `${color}33`;
                    e.target.style.transform = 'scale(1)';
                  }}
                >
                  🛒
                </button>
              </div>

              {product.productPage && (
                <Link
                  to={product.productPage}
                  onClick={() => window.scrollTo(0, 0)}
                  style={{
                    display: 'block',
                    width: '100%',
                    padding: '12px',
                    background: 'transparent',
                    border: `2px solid ${color}`,
                    borderRadius: '10px',
                    color: color,
                    fontSize: '1rem',
                    fontWeight: 'bold',
                    textAlign: 'center',
                    textDecoration: 'none',
                    transition: 'all 0.3s'
                  }}
                  onMouseEnter={(e) => {
                    e.target.style.background = `${color}33`;
                    e.target.style.transform = 'scale(1.02)';
                  }}
                  onMouseLeave={(e) => {
                    e.target.style.background = 'transparent';
                    e.target.style.transform = 'scale(1)';
                  }}
                >
                  VIEW FULL DETAILS →
                </Link>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <Layout pageTitle="🛒 Complete Product Catalog">
      <div style={{
        maxWidth: '1600px',
        margin: '0 auto 30px',
        padding: '0 20px',
        display: 'flex',
        gap: '10px',
        alignItems: 'center',
        fontSize: '1rem',
        color: '#FFD700'
      }}>
        <Link to="/" onClick={() => window.scrollTo(0, 0)} style={{ color: '#FFD700', textDecoration: 'none' }}>
          🏠 Home
        </Link>
        <span>→</span>
        <Link to="/MAVJStore" onClick={() => window.scrollTo(0, 0)} style={{ color: '#FFD700', textDecoration: 'none' }}>
          🛒 Store
        </Link>
        <span>→</span>
        <span style={{ color: '#FFF', fontWeight: 'bold', fontSize: '1.1rem' }}>Product Catalog</span>
      </div>

      <div style={{
        maxWidth: '1600px',
        margin: '0 auto 60px',
        padding: '60px 20px',
        background: 'linear-gradient(135deg, rgba(148,0,211,0.2), rgba(0,206,209,0.2))',
        borderRadius: '20px',
        border: '3px solid',
        borderImage: 'linear-gradient(45deg,violet,indigo,blue,green,yellow,orange,red) 1',
        textAlign: 'center'
      }}>
        <h1 style={{
          fontSize: 'clamp(2.5rem, 6vw, 4rem)',
          background: 'linear-gradient(135deg, #FFD700, #00CED1, #FF69B4, #9400D3)',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
          marginBottom: '20px',
          fontWeight: 'bold'
        }}>
          Complete Product Catalog
        </h1>
        <p style={{
          fontSize: '1.3rem',
          color: '#DDD6B8',
          maxWidth: '900px',
          margin: '0 auto',
          lineHeight: '1.8'
        }}>
          Every product. Every category. Your complete roadmap from foundation to convergence.
        </p>
      </div>

      <div style={{
        maxWidth: '1600px',
        margin: '0 auto 60px',
        padding: '30px',
        background: 'rgba(0,0,0,0.6)',
        borderRadius: '15px',
        border: '2px solid #FFD700'
      }}>
        <h3 style={{ color: '#FFD700', marginBottom: '20px', textAlign: 'center', fontSize: '1.5rem' }}>
          Jump to Category:
        </h3>
        <div style={{
          display: 'flex',
          flexWrap: 'wrap',
          gap: '15px',
          justifyContent: 'center'
        }}>
          {[
            { name: 'Sea Moss', id: 'seamoss', color: '#00CED1', icon: '🌊' },
            { name: 'Herbs', id: 'herbs', color: '#32CD32', icon: '🌿' },
            { name: 'Seeds', id: 'seeds', color: '#FFD700', icon: '🌱' },
            { name: 'Oils', id: 'oils', color: '#FF6B00', icon: '🔥' },
            { name: 'Kits', id: 'kits', color: '#9400D3', icon: '💎' },
            { name: 'Snacks', id: 'snacks', color: '#FFD700', icon: '✨' },
            { name: 'Beverages', id: 'beverages', color: '#4169E1', icon: '🥤' },
            { name: 'J2E', id: 'j2e', color: '#00CED1', icon: '🏝️' },
            { name: 'Merchandise', id: 'merchandise', color: '#FFD700', icon: '👕' }
          ].map(cat => (
            <a
              key={cat.id}
              href={`#${cat.id}`}
              style={{
                padding: '12px 25px',
                background: `${cat.color}20`,
                border: `2px solid ${cat.color}`,
                borderRadius: '25px',
                color: cat.color,
                textDecoration: 'none',
                fontSize: '1.1rem',
                fontWeight: 'bold',
                transition: 'all 0.3s'
              }}
              onMouseEnter={(e) => {
                e.target.style.background = `${cat.color}40`;
                e.target.style.transform = 'scale(1.05)';
              }}
              onMouseLeave={(e) => {
                e.target.style.background = `${cat.color}20`;
                e.target.style.transform = 'scale(1)';
              }}
            >
              {cat.icon} {cat.name}
            </a>
          ))}
        </div>
      </div>

      <div style={{ maxWidth: '1600px', margin: '0 auto', padding: '0 20px 80px' }}>
        <CategorySection 
          id="seamoss"
          title="Sea Moss - All Colors & Sizes"
          products={seaMossProducts}
          color="#00CED1"
          icon="🌊"
        />

        <CategorySection 
          id="herbs"
          title="Sacred Herbs"
          products={herbProducts}
          color="#32CD32"
          icon="🌿"
        />

        <CategorySection 
          id="seeds"
          title="Life Force Seeds"
          products={seedProducts}
          color="#FFD700"
          icon="🌱"
        />

        <CategorySection 
          id="oils"
          title="Sacred Oils"
          products={oilProducts}
          color="#FF6B00"
          icon="🔥"
        />

        <CategorySection 
          id="kits"
          title="Transformation Kits"
          products={kitProducts}
          color="#9400D3"
          icon="💎"
        />

        <CategorySection 
          id="snacks"
          title="Celebration Treats"
          products={snackProducts}
          color="#FFD700"
          icon="✨"
        />

        <CategorySection 
          id="beverages"
          title="Living Beverages"
          products={beverageProducts}
          color="#4169E1"
          icon="🥤"
        />

        <CategorySection 
          id="j2e"
          title="Journey 2 Enlightenment"
          products={j2eProducts}
          color="#00CED1"
          icon="🏝️"
        />

        <CategorySection 
          id="merchandise"
          title="MAVJ Gear"
          products={merchandiseProducts}
          color="#FFD700"
          icon="👕"
        />

        <div id="consultation" style={{
          marginTop: '80px',
          padding: '50px',
          background: 'linear-gradient(135deg, rgba(148,0,211,0.1), rgba(255,215,0,0.1))',
          borderRadius: '20px',
          border: '3px solid',
          borderImage: 'linear-gradient(45deg,violet,indigo,blue,green,yellow,orange,red) 1',
          textAlign: 'center'
        }}>
          <h2 style={{ color: '#9400D3', fontSize: '2.5rem', marginBottom: '20px' }}>
            💬 Personalized Consultation
          </h2>
          <p style={{ fontSize: '1.3rem', marginBottom: '30px', lineHeight: '1.8', color: '#DDD6B8', maxWidth: '800px', margin: '0 auto 30px' }}>
            Book a consultation with Robin for customized protocols aligned with your unique 
            frequency, health history, and transformation goals.
          </p>
          <Link 
            to="/ContactUs"
            onClick={() => window.scrollTo(0, 0)}
            style={{
              display: 'inline-block',
              padding: '18px 45px',
              background: 'linear-gradient(135deg, #9400D3, #FFD700)',
              color: '#000',
              textDecoration: 'none',
              borderRadius: '50px',
              fontSize: '1.3rem',
              fontWeight: 'bold',
              boxShadow: '0 8px 25px rgba(148,0,211,0.5)',
              transition: 'all 0.3s'
            }}
          >
            Schedule Consultation →
          </Link>
        </div>
      </div>

      <div style={{ textAlign: 'center', paddingBottom: '60px' }}>
        <button
          onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
          style={{
            padding: '15px 40px',
            background: 'linear-gradient(135deg, #FFD700, #FFA500)',
            border: 'none',
            borderRadius: '50px',
            color: '#000',
            fontSize: '1.2rem',
            fontWeight: 'bold',
            cursor: 'pointer',
            boxShadow: '0 5px 20px rgba(255,215,0,0.5)'
          }}
        >
          ↑ Back to Top
        </button>
      </div>
    </Layout>
  );
};

export default ProductCatalog;
      